// JSONB schema: accounts, orders, invoices stored as JSONB doc columns.
// accounts.preferredPaymentMethod: optional enum (credit_card, wire_transfer, ach, paypal)

let _schemaEnsured = false;

export async function ensureSchema(client) {
  if (_schemaEnsured) return;

  // Check if accounts table exists with a doc column; if not, drop and recreate
  const check = await client.query(`
    SELECT column_name FROM information_schema.columns
    WHERE table_name = 'accounts' AND column_name = 'doc'
  `);
  if (check.rows.length === 0) {
    await client.query(`DROP TABLE IF EXISTS invoices`);
    await client.query(`DROP TABLE IF EXISTS orders`);
    await client.query(`DROP TABLE IF EXISTS accounts`);
  }

  await client.query(`
    CREATE TABLE IF NOT EXISTS accounts (
      account_id TEXT PRIMARY KEY,
      doc JSONB NOT NULL,
      CONSTRAINT chk_accounts_preferred_payment_method CHECK (
        doc->>'preferredPaymentMethod' IS NULL OR
        doc->>'preferredPaymentMethod' IN ('credit_card', 'wire_transfer', 'ach', 'paypal')
      )
    )
  `);
  await client.query(`
    CREATE TABLE IF NOT EXISTS orders (
      order_id TEXT PRIMARY KEY,
      account_id TEXT,
      doc JSONB NOT NULL
    )
  `);
  await client.query(`
    CREATE TABLE IF NOT EXISTS invoices (
      invoice_id TEXT PRIMARY KEY,
      account_id TEXT,
      order_id TEXT,
      doc JSONB NOT NULL
    )
  `);

  _schemaEnsured = true;
}
